describe('notification ordering', () => {
  it('should deliver notifications in the order events are emitted', async () => {
    const orderCreatedEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    const statusChangedEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    // Emit both events sequentially — order:created first, then status change
    await eventBus.emit(orderCreatedEvent);
    await eventBus.emit(statusChangedEvent);

    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(2);
    // The order_confirmation must arrive before the order_status_update
    expect(notifications[0]?.type).toBe('order_confirmation');
    expect(notifications[1]?.type).toBe('order_status_update');

    // Verify adapter delivery order matches as well
    const emails = emailAdapter.getSentEmails();
    expect(emails).toHaveLength(2);
    expect(emails[0]?.subject).toContain('Order Confirmation');
    expect(emails[1]?.subject).toContain('Order Update');
  });
});

